module piso_shift_register (
	input clk,
	input reset,
	input load,
	input [7:0] data_in,
	output reg data_out
);reg [7:0] reverse_reg;

always @(posedge clk) begin
	if (reset)
		reverse_reg <= 8'b00000000;
	else if (load)
		reverse_reg <= data_in;
	else
		reverse_reg <= reverse_reg >> 1;
end

always @(reverse_reg) begin
	data_out <= reverse_reg[0];
end

endmodule
